import React, { useEffect, useMemo, useState } from 'react';
import { Bar, Doughnut } from 'react-chartjs-2';
import { ArcElement, BarElement, CategoryScale, Chart as ChartJS, Legend, LinearScale, Tooltip } from 'chart.js';
import api from '../../utils/api';
ChartJS.register(CategoryScale, LinearScale, BarElement, ArcElement, Tooltip, Legend);
const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const currency = v => Number(v || 0).toLocaleString('en-IN', { style: 'currency', currency: 'INR', maximumFractionDigits: 0 });
const ReportsAnalyticsModule = () => {
  const [year, setYear] = useState(new Date().getFullYear()); const [report, setReport] = useState(null); const [loading, setLoading] = useState(true);
  useEffect(() => { const load = async () => { setLoading(true); try { const res = await api.get('/reports/overview', { params: { year } }); setReport(res.data); } catch (_) { setReport(null); } finally { setLoading(false); } }; load(); }, [year]);
  const financeChart = useMemo(() => { const revenue = Array(12).fill(0); const expenses = Array(12).fill(0); report?.monthly_finance?.forEach(r => { revenue[Number(r.month)-1] = Number(r.revenue || 0); expenses[Number(r.month)-1] = Number(r.expenses || 0); }); return { labels: months, datasets: [{ label: 'Revenue', data: revenue, backgroundColor: 'rgba(22,163,74,0.78)', borderRadius: 10 }, { label: 'Expenses', data: expenses, backgroundColor: 'rgba(220,38,38,0.72)', borderRadius: 10 }] }; }, [report]);
  const attendanceChart = useMemo(() => ({ labels: ['Present','Late','Absent'], datasets: [{ data: [report?.attendance?.present || 0, report?.attendance?.late || 0, report?.attendance?.absent || 0], backgroundColor: ['#16a34a','#d97706','#dc2626'] }] }), [report]);
  const options = { responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'top' } }, scales: { y: { beginAtZero: true, grid: { color: '#edf2f7' } }, x: { grid: { display: false } } } };
  return <div><div className="page-header"><div><p className="eyebrow">Business Intelligence</p><h1 className="page-title">Reports and Analytics Module</h1><p className="page-subtitle">Combined analytics from HR, CRM, sales, purchase, inventory, attendance and finance.</p></div><select className="select" value={year} onChange={e => setYear(Number(e.target.value))} style={{ width: 170 }}><option>2024</option><option>2025</option><option>2026</option><option>2027</option></select></div>{loading ? <div className="loading-state card"><div><div className="loading-spinner" /><p>Preparing reports...</p></div></div> : !report ? <div className="empty-state card"><div><div className="empty-icon">📊</div><p>Unable to load reports. Run migration and seed first.</p></div></div> : <><div className="grid grid-4" style={{ marginBottom: 20 }}><div className="card metric-card" style={{ '--metric-color': '#2563eb', '--metric-soft': '#dbeafe' }}><div className="metric-top"><p className="metric-label">Employees</p><span className="metric-icon">👥</span></div><p className="metric-value">{report.employees}</p><p className="metric-sub">Active workforce</p></div><div className="card metric-card" style={{ '--metric-color': '#7c3aed', '--metric-soft': '#ede9fe' }}><div className="metric-top"><p className="metric-label">Customers</p><span className="metric-icon">◎</span></div><p className="metric-value">{report.customers}</p><p className="metric-sub">CRM records</p></div><div className="card metric-card" style={{ '--metric-color': '#16a34a', '--metric-soft': '#dcfce7' }}><div className="metric-top"><p className="metric-label">Sales</p><span className="metric-icon">₹</span></div><p className="metric-value">{currency(report.sales_value)}</p><p className="metric-sub">Invoice amount</p></div><div className="card metric-card" style={{ '--metric-color': '#d97706', '--metric-soft': '#fef3c7' }}><div className="metric-top"><p className="metric-label">Stock Value</p><span className="metric-icon">▦</span></div><p className="metric-value">{currency(report.stock_value)}</p><p className="metric-sub">Inventory value</p></div></div><div className="grid grid-4" style={{ marginBottom: 20 }}><div className="card metric-card" style={{ '--metric-color': '#0891b2', '--metric-soft': '#cffafe' }}><div className="metric-top"><p className="metric-label">Revenue</p><span className="metric-icon">↗</span></div><p className="metric-value">{currency(report.revenue)}</p><p className="metric-sub">Finance {year}</p></div><div className="card metric-card" style={{ '--metric-color': '#dc2626', '--metric-soft': '#fee2e2' }}><div className="metric-top"><p className="metric-label">Expenses</p><span className="metric-icon">↘</span></div><p className="metric-value">{currency(report.expenses)}</p><p className="metric-sub">Finance {year}</p></div><div className="card metric-card" style={{ '--metric-color': '#16a34a', '--metric-soft': '#dcfce7' }}><div className="metric-top"><p className="metric-label">Net Profit</p><span className="metric-icon">◎</span></div><p className="metric-value">{currency(report.net_profit)}</p><p className="metric-sub">Revenue minus expense</p></div><div className="card metric-card" style={{ '--metric-color': '#7c3aed', '--metric-soft': '#ede9fe' }}><div className="metric-top"><p className="metric-label">Purchases</p><span className="metric-icon">▤</span></div><p className="metric-value">{report.purchase_orders}</p><p className="metric-sub">{currency(report.purchase_value)}</p></div></div><div className="grid grid-2"><section className="card chart-card"><div className="chart-header"><div><h3 className="card-title">Revenue vs Expenses</h3><p className="card-subtitle">Month wise business performance.</p></div></div><div className="chart-wrap"><Bar data={financeChart} options={options} /></div></section><section className="card chart-card"><div className="chart-header"><div><h3 className="card-title">Attendance Status</h3><p className="card-subtitle">Present, late and absent distribution.</p></div></div><div className="chart-wrap"><Doughnut data={attendanceChart} options={{ responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'bottom' } } }} /></div></section></div></>}</div>;
};
export default ReportsAnalyticsModule;
